import { precompileTemplate } from "@ember/template-compilation";
export default precompileTemplate("<LfGetOutletState as |outletState|>\n  {{~!~}}\n  <LiquidBind\n    @value={{(lf-lock-model outletState this.outletName)}}\n    @containerId={{@containerId}}\n    @versionEquality={{this.versionEquality}}\n    @matchContext={{(hash outletName=this.outletName helperName=\"liquid-outlet\")}}\n    @class={{@class}}\n    @use={{@use}}\n    @rules={{@rules}}\n    @containerless={{@containerless}}\n    @containerElement={{@containerElement}}\n    @growDuration={{@growDuration}}\n    @growPixelsPerSecond={{@growPixelsPerSecond}}\n    @growEasing={{@growEasing}}\n    @shrinkDelay={{@shrinkDelay}}\n    @growDelay={{@growDelay}}\n    @enableGrowth={{@enableGrowth}} as |version|\n  >\n  {{~!~}}\n    {{~#-with-dynamic-vars outletState=version~}}\n      {{!-- template-lint-disable no-outlet-outside-routes --}}\n      {{~outlet~}}\n    {{~/-with-dynamic-vars~}}\n  {{~!~}}\n  </LiquidBind>\n  {{~!~}}\n</LfGetOutletState>")